本文并不实现一个完整的 SOA 数据结构，而是探索在 Zig 中如何简单、高效的实现一个 SOA 数据结构，以及是否能够到到足够的高性能。 参考如下的代码示例 const Node = struct { a: u32, b: u8
}; // 下一步使用 comptime 生成一个 SOA 的数据结构
// fn SOA(structure: type, N: comptime_int) type {
// // } // 这个示例使用手写版本的 SOA fn NodeSOA(N: comptime_int) type { const result = struct { a: [N]u32, b: [N]u8, fn init() NodeSOA(N) { return NodeSOA(N) { .a = undefined, .b = undefined, }; } fn get(self: *NodeSOA(N), index: u32) Node { return Node{ .a = self.a[index], .b = self.b[index] }; } fn set(self: *NodeSOA(N), index: u32, node: Node) void { self.a[index] = node.a; self.b[index] = node.b; } }; return result;
}

