上述的实现中，我很好奇的是，如果我们需要访问 soa[index].x 这样的操作，是否是高效的。由于 zig 不支持运算符重载，因此，语法为： soa.get(index).x, soa.get(index) 会有一个构造 Node 的操作，如果字段较多，会涉及到很多的字段赋值，返回值作为值的传递也会有很大的开销。 我们实际上仅用到 x 字段，其他的字段其实是没有被使用到了。 带着对这个问题的好奇，我做一个简单的测试： pub fn main() !void { var nodes = NodeSOA(10).init(); // get argv[1] and convert it to u32 // const arg = std.os.args.arg(1); var args = std.process.args(); defer args.deinit(); _ = args.skip(); const arg1 = args.next(); const index: u32 = if(arg1) |x| try std.fmt.parseInt(u32, x, 10) else 0; nodes.set(0, Node{ .a = 1, .b = 2 }); nodes.set(1, Node{ .a = 3, .b = 4 }); nodes.set(2, Node{ .a = 5, .b = 6 }); nodes.set(3, Node{ .a = 7, .b = 8 }); nodes.set(4, Node{ .a = 9, .b = 10 }); nodes.set(5, Node{ .a = 11, .b = 12 }); nodes.set(6, Node{ .a = 13, .b = 14 }); nodes.set(7, Node{ .a = 15, .b = 16 }); nodes.set(8, Node{ .a = 17, .b = 18 }); nodes.set(9, Node{ .a = 19, .b = 20 }); var x: u32 = 123; print("x = {}
", .{x}); // 重点关注这几段代码生成的asm代码： x += nodes.get(index).a; x += nodes.get(index).b; print("x = {}
", .{x}); x += nodes.get(index+1).a; x += nodes.get(index+1).b; print("x = {}
", .{x});
} 在 ReleaseSmall/ReleaseFast 模式下： lea	rdi, [rsp + 48] mov	dword ptr [rdi], 123 call	_debug.print__anon_1219 mov	r14d, r14d mov	eax, dword ptr [rsp + 4*r14 + 56] // nodes.get(index).a movzx	ecx, byte ptr [rsp + r14 + 96] // nodes.get(index).b lea	ebp, [rax + rcx] add	ebp, 123 lea	rdi, [rsp + 52] mov	dword ptr [rdi], ebp call	_debug.print__anon_1219 add	ebp, dword ptr [rsp + 4*r14 + 60] // nodes.get(index+1).a movzx	eax, byte ptr [rsp + r14 + 97] // nodes.get(index+1).b add	eax, ebp lea	rdi, [rsp + 24] mov	dword ptr [rdi], eax call	_debug.print__anon_1219 可以看到，nodes.get(index).a 这样的操作已经被优化成了与手写代码一样的效率，这些应该是 LLVM IR 优化带来的巨大价值。 当然，在 Debug 模式下，是不会进行这个优化的。

