fn max(comptime T: type, a: T, b: T) T { return if (a > b) a else b;
} // 这个方法是有错误的，但因为没有被调用，所以编译时并不报错
fn do_sth(comptime T: type): T { return T.MAX_VALUE; // } // 这个方法是有错误的，但因为没有被调用，所以编译时并不报错
fn do_sth2() i16 { return i16.MAX_VALUE;
} test "try to pass a runtime type" { foo(false);
}
fn foo(condition: bool) void { // fn foo(comptime condition: bool) void { // change condition to comptime will fix the error const result = max(if (condition) f32 else u64, 1234, 5678); // error: condition is not a comptime value _ = result;
} type 是一个元类型，其值是一个类型，这个类型只能出现在编译期。zig 并没有提供 type 这个类型的内部结构（一般的，运行期所有的类型 都有自己的 layout 结构，但是 zig 语言中并没有定义 type 的 layout 结构），其内部结构是一个 opaque 的值，且仅能在 compile time 中存在。 comptime parameter 为 ziglang 提供了 generic 机制， 实际调用方法时，会为 comptime parameter 参数展开。 zig 的 generic 处理，更类似于 C++ 的 template，而非 Rust 的 generic。 参考上例，do_sth 中的 T.MAX_VALUE 是一个 无效的访问，但是因为没有被调用，所以编译器并不会报错。 不仅对 generic 的方法，对普通的方法，如果没有被调用，编译器也不会报错。
